import { z } from 'zod';

// â”€â”€ Read-only levels â”€â”€

export type ReadOnlyLevel = 'enforced' | 'bestEffort' | 'none';

// â”€â”€ Config schemas (zod) â”€â”€

export const ToolConfigSchema = z.object({
  binary: z.string(),
  adapter: z.string().optional(),
  readOnly: z.object({
    level: z.enum(['enforced', 'bestEffort', 'none']),
    flags: z.array(z.string()).optional(),
  }),
  extraFlags: z.array(z.string()).optional(),
  timeout: z.number().optional(),
  stdin: z.boolean().optional(),
  custom: z.boolean().optional(),
});

export type ToolConfig = z.infer<typeof ToolConfigSchema>;

export const ConfigSchema = z.object({
  version: z.literal(1),
  defaults: z
    .object({
      timeout: z.number().default(900),
      outputDir: z.string().default('./agents/counselors'),
      readOnly: z
        .enum(['enforced', 'bestEffort', 'none'])
        .default('bestEffort'),
      maxContextKb: z.number().default(50),
      maxParallel: z.number().default(4),
    })
    .default({}),
  tools: z.record(z.string(), ToolConfigSchema).default({}),
  groups: z.record(z.string(), z.array(z.string())).default({}),
});

export type Config = z.infer<typeof ConfigSchema>;

// â”€â”€ Runtime types â”€â”€

export interface RunRequest {
  prompt: string;
  promptFilePath: string;
  toolId: string;
  outputDir: string;
  readOnlyPolicy: ReadOnlyLevel;
  timeout: number;
  cwd: string;
  binary?: string;
  extraFlags?: string[];
}

export interface Invocation {
  cmd: string;
  args: string[];
  env?: Record<string, string>;
  stdin?: string;
  cwd: string;
}

export interface ExecResult {
  exitCode: number;
  stdout: string;
  stderr: string;
  timedOut: boolean;
  durationMs: number;
}

export interface CostInfo {
  cost_usd: number;
  free_used_usd: number;
  credits_used_usd: number;
  source: 'free' | 'credits';
  free_remaining_usd: number;
  free_total_usd: number;
  credits_remaining_usd: number;
}

export interface ToolReport {
  toolId: string;
  status: 'success' | 'error' | 'timeout' | 'skipped';
  exitCode: number;
  durationMs: number;
  wordCount: number;
  outputFile: string;
  stderrFile: string;
  cost?: CostInfo;
  error?: string;
}

// â”€â”€ Adapter interface â”€â”€

export interface ToolAdapter {
  id: string;
  displayName: string;
  commands: string[];
  installUrl: string;
  readOnly: { level: ReadOnlyLevel };
  modelFlag?: string;
  models: {
    id: string;
    name: string;
    recommended?: boolean;
    compoundId?: string;
    extraFlags?: string[];
  }[];
  buildInvocation(req: RunRequest): Invocation;
  parseResult?(result: ExecResult): Partial<ToolReport>;
  /** Return the effective read-only level for a specific tool configuration.
   *  Adapters override this when certain models have weaker enforcement. */
  getEffectiveReadOnlyLevel?(toolConfig: ToolConfig): ReadOnlyLevel;
}

// â”€â”€ Discovery â”€â”€

export interface DiscoveryResult {
  toolId: string;
  found: boolean;
  path: string | null;
  version: string | null;
}

// â”€â”€ Doctor â”€â”€

export interface DoctorCheck {
  name: string;
  status: 'pass' | 'fail' | 'warn';
  message: string;
}

// â”€â”€ Test â”€â”€

export interface TestResult {
  toolId: string;
  passed: boolean;
  output: string;
  error?: string;
  durationMs: number;
  command?: string;
}

// â”€â”€ Round manifest (multi-round mode) â”€â”€

export interface RoundManifest {
  round: number;
  timestamp: string;
  tools: ToolReport[];
}

// â”€â”€ Run manifest â”€â”€

export interface RunManifest {
  timestamp: string;
  slug: string;
  prompt: string;
  promptSource: 'inline' | 'file' | 'stdin';
  readOnlyPolicy: ReadOnlyLevel;
  tools: ToolReport[];
  rounds?: RoundManifest[];
  totalRounds?: number;
  durationMs?: number;
  preset?: string;
}
